{"meta": null, "content": [{"type": "text", "text": "{"content":"405:     return outsize \u003e int_max;\n406:   }\n407: \n408:   bool use_cudnn(const at::Tensor\u0026 input, const at::Tensor\u0026 weight) const {\n409:   // Note [Mobile check segfaults]\n410:   // cudnn and miopen are guaranteed not to be on mobile, and T102591915 / T110194934 suggest\n411:   // that maybe the compiledWithCuDNN() check sometimes segfaults (though I can't imagine how)\n412: #if !defined(C10_MOBILE)\n413:     if (!detail::getCUDAHooks().compiledWithCuDNN() || !input.is_cuda() || !cudnn_enabled) {\n414:       return false;\n415:     }\n416:     static long cudnn_version = detail::getCUDAHooks().versionRuntimeCuDNN();\n417:     // broken on cuDNN 9.8 - 9.14\n418:     if (cudnn_version \u003e= 90800 \u0026\u0026 cudnn_version \u003c 91500) {\n419:       if (cudnn_conv_suggest_memory_format(input, weight) == at::MemoryFormat::Contiguous \u0026\u0026\n420:           (input.scalar_type() == at::kBFloat16 || input.scalar_type() == at::kHalf) \u0026\u0026\n421:           weight.dim() == 5) {\n422:         for (int i = 2; i \u003c weight.dim(); i++) {\n423:           if (weight.size(i) != 1) {\n424:             return false;\n425:           }\n426:         }\n427:       }\n428:     }\n429:     if (needs_64bit_indexing_no_split(input, weight)) {\n430:       if (!(cudnn_version \u003e= 90300 \u0026\u0026 at::native::cudnnv8_enabled_check_debug())) {\n431:         TORCH_WARN_ONCE(\"cuDNN cannot be used for large non-batch-splittable convolutions\"\n432:                         \" if the V8 API is not enabled or before cuDNN version 9.3+.\"\n433:                         \" Consider upgrading cuDNN and/or enabling the V8 API for better efficiency.\");\n434:         return false;\n435:       }\n436:     }\n437:     if (input.scalar_type() == at::kBFloat16 || weight.scalar_type() == at::kBFloat16) {\n438:       if (!(detail::getCUDAHooks().supportsBFloat16ConvolutionWithCuDNNv8() \u0026\u0026 at::native::cudnnv8_enabled_check_debug())) {\n439:         return false;\n440:       }\n441:     }\n442:     if (cudnn_conv_suggest_memory_format(input, weight) == at::MemoryFormat::Contiguous) {\n443:       if (is_dilated()) {\n444:         return detail::getCUDAHooks().supportsDilatedConvolutionWithCuDNN() \u0026\u0026 !is_output_padding_big();\n445:       }\n446:     }\n447:     return !is_output_padding_big();\n448: #else\n449:     return false;\n450: #endif\n451:   }\n452: \n453:   // Use cudnn for FP16 depthwise convolutions\n454:   bool use_cudnn_depthwise(const at::Tensor\u0026 input, const at::Tensor\u0026 weight) const  {\n455:     if (!cudnn_enabled || !detail::getCUDAHooks().compiledWithCuDNN() || !input.is_cuda()) {\n456:       return false;\n457:     }\n458:     // native kernel doesn't support 64-bit non-splittable case\n459:     if (!(canUse32BitIndexMath(input) \u0026\u0026 canUse32BitIndexMath(weight))) {\n460:       static long cudnn_version = detail::getCUDAHooks().compiledWithCuDNN() ? detail::getCUDAHooks().versionRuntimeCuDNN() : -1;\n461:       // TODO(eqy): remove this once cuDNN fixes 64-bit depthwise support, first broken in 9.11x\n462:       if (cudnn_conv_suggest_memory_format(input, weight) != at::MemoryFormat::Contiguous) {\n463:         if (cudnn_version \u003c 0 || cudnn_version \u003e 91000) {\n464:           return false;\n465:         }\n466:       }\n467: \n468:       if (!(cudnn_version \u003e= 90300 \u0026\u0026 at::native::cudnnv8_enabled_check_debug())) {\n469:         TORCH_WARN_ONCE(\"cuDNN cannot be used for large non-batch-splittable convolutions\"\n470:                         \" if the V8 API is not enabled or before cuDNN version 9.3+.\"\n471:                         \" Upgrade cuDNN or enable the V8 API to use cuDNN for 64-bit depthwise convolutions.\");\n472:         return false;\n473:       } else {\n474:         return true;\n475:       }\n476:     }\n477:     if (cudnn_conv_suggest_memory_format(input, weight) != at::MemoryFormat::Contiguous) {\n478:       // always use cudnn_depthwise for channels_last format\n479:       return true;\n480:     }\n481: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/pytorch--5811a8d7@5811a8d7da873dd699ff6687092c225caffcf1bb/-/blob/aten/src/ATen/native/Convolution.cpp%3FL405-480"}", "annotations": null, "meta": null}], "structuredContent": {"content": "405:     return outsize > int_max;
