115: bool CUDAHooks::isPinnedPtr(const void* data) const {
116:   // First check if driver is broken/missing, in which case PyTorch CPU
117:   // functionalities should still work, we should report `false` here.
118:   if (!at::cuda::is_available()) {
119:     return false;
120:   }
121:   // cudaPointerGetAttributes grabs context on the current device, so we set
122:   // device to one that already has context, if exists.
123:   at::OptionalDeviceGuard device_guard;
124:   auto primary_ctx_device_index = getDeviceIndexWithPrimaryContext();
125:   if (primary_ctx_device_index.has_value()) {
126:     device_guard.reset_device(at::Device(at::DeviceType::CUDA, *primary_ctx_device_index));
127:   }
128:   cudaPointerAttributes attr{};
129:   // We do not believe that CUDA needs mutable access to the data
130:   // here.
131:   cudaError_t err = cudaPointerGetAttributes(&attr, data);
132: #if !defined(USE_ROCM)
133:   if (err == cudaErrorInvalidValue) {
134:     (void)cudaGetLastError(); // clear CUDA error
135:     return false;
136:   }
137:   AT_CUDA_CHECK(err);
138: #else
139:   // HIP throws hipErrorUnknown here
140:   if (err != cudaSuccess) {
141:     (void)cudaGetLastError(); // clear HIP error
142:     return false;
143:   }
144: #endif
145:   return attr.type == cudaMemoryTypeHost;
146: }
