61: namespace sdp {
62: namespace {
63: 
64: // tracks whether we've set the default priority order once, to avoid setting
65: // it redundantly or overwriting a user-specified priority order
66: // when the priority order context manager is used before the default priority
67: // order is initialized the following happens:
68: // (1) the current priority order is queried
69: // (2) priority_order() is called, which initializes it to the default as init_ is false
70: // (3) the user-specified priority order is set
71: // (3.1) we are in the priority context...
72: // (3.2) we exit the priority context...
73: // (4) the previous priority order (default) is restored
74: bool priority_order_init_ = false;
75: 
76: // TODO(eqy): more benchmarking to determine whether this should include sm86/89
77: // Needs to be kept in-sync with test_fused_chocie in test_transformers.py
78: bool check_prefer_cudnn_attention() {
79:   static const bool prefer_cudnn = c10::utils::check_env("TORCH_CUDNN_SDPA_PREFERRED") != false;
80:   if (!prefer_cudnn) {
81:     return false;
82:   }
83: #if (defined(CUDNN_VERSION) && (CUDNN_VERSION >= 90900))
84:   auto dprops = at::cuda::getCurrentDeviceProperties();
85:   auto major = dprops->major;
86:   return (major == 9 || major == 10) && !dprops->minor;
87: #else
88:   return false;
89: #endif
90: }
91: 
92: // flash_attention V2 is universally faster than efficient_attention and Math
93: std::array<SDPBackend, num_backends> priority_order(sdp_params const& params) {
94:   if (!priority_order_init_) {
95:     priority_order_init_ = true;
96:     if (check_prefer_cudnn_attention()) {
97:         const std::vector<int64_t> cudnn_order = {static_cast<int64_t>(at::SDPBackend::cudnn_attention),
98:                                                   static_cast<int64_t>(at::SDPBackend::flash_attention),
99:                                                   static_cast<int64_t>(at::SDPBackend::efficient_attention),
100:                                                   static_cast<int64_t>(at::SDPBackend::math)};
101:         at::globalContext().setSDPPriorityOrder(cudnn_order);
102:     }
103:   }
104:   return at::globalContext().sDPPriorityOrder();
105: }
106: 
107: bool use_tensor_cores(sdp_params const& params, cudaDeviceProp* dprops, bool is_half) {
108:   if (dprops->major >= 8) {
109:     return true;
110:   }
111:   if (dprops->major >= 7) {
112:     return is_half;
113:   }
114:   return false;
115: }
116: int64_t minimum_gemm_alignment(sdp_params const& params) {
117:   auto dprops = at::cuda::getCurrentDeviceProperties();
118:   bool is_half = (params.query.dtype() == at::kHalf) ||
119:       (params.query.dtype() == at::kBFloat16);
120:   bool use_tc = use_tensor_cores(params, dprops, is_half);
121:   int64_t matmul_alignment_mn = 1;
122:   if (dprops->major >= 8) {
123:     matmul_alignment_mn = 4;
124:   }
125:   int64_t bits_per_scalar = is_half ? 16 : 32;
126:   if (use_tc) {
127:     matmul_alignment_mn = std::max(matmul_alignment_mn, 128 / bits_per_scalar);
128:   }
129:   return matmul_alignment_mn;
130: }
