364: bool check_requires_grad_and_head_dim_gt192_constraints_on_sm86_89_or_120(
365:     sdp_params const& params,
366:     bool debug) {
367:   // Flash Attention will raise an error in the backward pass if the head_dim
368:   // size is greater than 192 And the device is between in the range [sm86, sm89]
369:   using sm86 = SMVersion<8, 6>;
370:   using sm89 = SMVersion<8, 9>;
371:   using sm120 = SMVersion<12, 0>;
372:   using sm121 = SMVersion<12, 1>;
373:   auto dprops = at::cuda::getCurrentDeviceProperties();
374:   bool is_sm86_or_sm89 = check_sm_version<sm86, sm89>(dprops);
375:   bool is_sm120_or_sm121 = check_sm_version<sm120, sm121>(dprops);
376:   bool is_head_dim_gt192 = params.query.sym_size(-1) > 192;
377:   bool is_head_dim_lte224 = params.query.sym_size(-1) <= 224;
378:   bool is_dropout = params.dropout > 0.0;
379:   //  head_dim size  in (192, 224] is not supported on sm86 and sm89
380:   bool cond1 = is_head_dim_gt192 && is_head_dim_lte224;
381:   // head_dim size > 224 and is_dropout is not supported on sm86 and sm89
382:   bool cond2 = params.query.sym_size(-1) > 224 && is_dropout;
383:   if (input_requires_grad(params) && (is_sm86_or_sm89 || is_sm120_or_sm121) && (cond1 || cond2)) {
384:     if (debug) {
385:       TORCH_WARN(
386:           "Flash attention currently doesn't support training with head_dim ∈ (192, 224] or "
387:           "(head_dim ∈ (224, 256] and dropout > 0.0) on gpu architectures in the range[sm86, sm89].",
388:           "Attempting to run with dropout set to: ", params.dropout,
389:           "and head_dim: ",
390:           params.query.sym_size(-1), " on a sm ", dprops->major, ".",
391:           dprops->minor, " gpu.");
392:     }
393:     return false;
394:   }
395:   return true;
396: }
