398: bool check_flash_causal_non_square_seqlens(sdp_params const& params, bool debug) {
399:   // FlashAttention 2 updated the default mask meaning for causal in this PR:
400:   // 9e5e8bc91e it is now aligned to lower_right which would be a BC break
401:   // for non-square masks. We will not support non-square masks for causal w/ FAV2
402:   if (params.is_causal &&
403:       !params.query.is_nested() && !params.key.is_nested() &&
404:       params.query.sym_size(-2) != params.key.sym_size(-2)) {
405:     if (debug) {
406:       TORCH_WARN(
407:           "Flash attention does not support the is_causal flag when seqlen_q != seqlen_k. ",
408:           "Got seqlen_q: ", params.query.sym_size(-2), " seqlen_k: ",
409:           params.key.sym_size(-2), ". If you would like to use causal attention with non-square masks, please see CausalAttnMask.");
410:     }
411:     return false;
412:   }
413:   return true;
414: }
