508: bool check_cudnn_layout(sdp_params const& params, bool debug) {
509:   const int64_t h = params.query.size(1);
510:   const int64_t s_q = params.query.size(2);
511:   const int64_t d = params.query.size(3);
512:   const int64_t s_k = params.key.size(2);
513:   const int64_t s_v = params.value.size(2);
514:   // corresponds to cuDNN's "packed QKV" layout
515:   const bool packed_query_layout_ok = (params.query.stride(0) == s_q * 3 * h * d) &&
516:                                  (params.query.stride(1) == d) &&
517:                                  (params.query.stride(2) == 3 * h * d) &&
518:                                  (params.query.stride(3) == 1);
519:   const bool packed_key_layout_ok = (params.key.stride(0) == s_k * 3 * h * d) &&
520:                                (params.key.stride(1) == d) &&
521:                                (params.key.stride(2) == 3 * h * d) &&
522:                                (params.key.stride(3) == 1);
523:   const bool packed_value_layout_ok = (params.value.stride(0) == s_v * 3 * h * d) &&
524:                                  (params.value.stride(1) == d) &&
525:                                  (params.value.stride(2) == 3 * h * d) &&
526:                                  (params.value.stride(3) == 1);
527: 
528:   const bool packed_layout_ok = packed_query_layout_ok && packed_key_layout_ok && packed_value_layout_ok;
529: 
530:   const bool query_layout_ok = (params.query.stride(0) == s_q * h * d) &&
531:                                (params.query.stride(1) == d) &&
532:                                (params.query.stride(2) == h * d) &&
533:                                (params.query.stride(3) == 1);
534:   const bool key_layout_ok = (params.key.stride(0) == s_k * h * d) &&
535:                               (params.key.stride(1) == d) &&
536:                               (params.key.stride(2) == h * d) &&
537:                               (params.key.stride(3) == 1);
538:   const bool value_layout_ok = (params.value.stride(0) == s_v * h * d) &&
539:                                (params.value.stride(1) == d) &&
540:                                (params.value.stride(2) == h * d) &&
541:                                (params.value.stride(3) == 1);
542: 
543:   const bool layout_ok = query_layout_ok && key_layout_ok && value_layout_ok;
544: 
545:   if (!packed_value_layout_ok && !layout_ok) {
546:     if (debug) {
547:       if (!packed_layout_ok) {
548:         if (!packed_query_layout_ok) {
549:           TORCH_WARN("Query tensor was not in cuDNN-supported packed QKV layout", params.query.strides());
550:         }
551:         if (!packed_key_layout_ok) {
552:           TORCH_WARN("Key tensor was not in cuDNN-supported packed QKV layout", params.key.strides());
553:         }
554:         if (!packed_value_layout_ok) {
555:           TORCH_WARN("Value tensor was not in cuDNN-supported packed QKV layout", params.value.strides());
556:         }
557:       }
558:       if (!layout_ok) {
559:         if (!query_layout_ok) {
560:           TORCH_WARN("Query tensor was not in cuDNN-supported unpacked QKV layout", params.query.strides());
561:         }
562:         if (!key_layout_ok) {
563:           TORCH_WARN("Key tensor was not in cuDNN-supported unpacked QKV layout", params.key.strides());
564:         }
565:         if (!value_layout_ok) {
566:           TORCH_WARN("Value tensor was not in cuDNN-supported unpacked QKV layout", params.value.strides());
567:         }
568:       }
569:     }
570:     return false;
571:   }
572:   return true;
573: }
