575: bool check_cudnn_hardware_support(sdp_params const& params, bool debug) {
576:   using sm80 = SMVersion<8, 0>;
577:   using sm121 = SMVersion<12, 1>;
578:   auto dprops = at::cuda::getCurrentDeviceProperties();
579:   if (!check_sm_version<sm80, sm121>(dprops)) {
580:     if (debug) {
581:       TORCH_WARN(
582:           "cuDNN MHA only supports gpu architectures in the range [sm80, sm121]. Attempting to run on a sm ",
583:           dprops->major,
584:           ".",
585:           dprops->minor,
586:           " gpu.");
587:     }
588:     return false;
589:   }
590:   return true;
591: }
