593: bool check_for_nested_inputs(sdp_params const& params, bool debug) {
594:   static const bool enable_cudnn_nested = c10::utils::check_env("TORCH_CUDNN_SDPA_NESTED_TENSOR_ENABLED") == true;
595:   if (has_for_nested_inputs(params) && !enable_cudnn_nested) {
596:     if (debug) {
597:       TORCH_WARN("Experimental cuDNN SDPA nested tensor support is not enabled.");
598:     }
599:     return false;
600:   } else if (has_for_nested_inputs(params) && (params.query.requires_grad() || params.key.requires_grad() || params.value.requires_grad())) {
601:     if (debug) {
602:       TORCH_WARN("Experimental cuDNN SDPA nested tensor support does not support backward.");
603:       return false;
604:     }
605:   }
606: 
607:   const auto dprop = at::cuda::getCurrentDeviceProperties();
608:   // Check that the input is nested
609:   if (!(dprop->major == 9 || dprop->major == 10) && has_for_nested_inputs(params)) {
610:     if (debug) {
611:       TORCH_WARN("cuDNN SDPA supports nested tensors on SM 9.0, SM 10.0.");
612:     }
613:     return false;
614:   }
615:   return true;
616: }
