618: bool check_dtypes_low_precision(sdp_params const& params, bool debug) {
619:   auto dprop = at::cuda::getCurrentDeviceProperties();
620:   if (dprop->major >= 8) {
621:     constexpr auto sm80_dtypes =
622:         c10::array_of<at::ScalarType>(at::kHalf, at::kBFloat16);
623:     return check_tensor_dtype(params, sm80_dtypes, debug);
624:   } else {
625:     constexpr auto default_dtypes = c10::array_of<at::ScalarType>(at::kHalf);
626:     return check_tensor_dtype(params, default_dtypes, debug);
627:   }
628: }
