511:   bool use_mkldnn(const at::Tensor& input, const at::Tensor& weight) const  {
512: #if AT_MKLDNN_ENABLED()
513:     if (!at::globalContext().userEnabledMkldnn()) {
514:       return false;
515:     }
516:     if (transposed && is_output_padding_big()) {
517:       return false;
518:     }
519:     if (input.device().is_cpu() &&
520:         ((input.scalar_type() == at::kBFloat16 && mkldnn_bf16_device_check()) ||
521:          (input.scalar_type() == at::kHalf && mkldnn_fp16_device_check()))) {
522:       return true;
523:     }
524:     return (input.is_mkldnn()) || // input is mkldnn Tensor
525:       (input.device().is_cpu() &&
526:        input.scalar_type() == kFloat && // only on CPU Float Tensors
527:        // For 1x1 filters, MKLDNN is faster than THNN when multi-threaded,
528:        // but THNN is faster when single-threaded.
529:        (is_strided() || is_dilated() || at::symint::size<T>(input, 0) >= 16 ||
530:         at::symint::size<T>(weight, -1) != 1 || at::symint::size<T>(weight, -2) != 1 || at::get_num_threads() > 1) &&
531:        (groups > 1
532:         || (at::symint::size<T>(weight, -1) > 3 && at::symint::size<T>(weight, -2) > 3)
533:         || at::symint::size<T>(input, 0) > 1
534:         || at::symint::size<T>(input, 0)*at::symint::size<T>(input, 1)*at::symint::size<T>(input, 2)*at::symint::size<T>(input, 3) > 20480) // for some case, native is faster
535:         );
