540:   bool use_nnpack(const at::Tensor& input, const at::Tensor& weight) const  {
541: #if AT_NNPACK_ENABLED()
542:     return at::globalContext().userEnabledNNPACK() &&
543:            at::_nnpack_available() &&
544:            input.device().is_cpu() &&
545:            input.scalar_type() == kFloat && // only on CPU Float Tensors
546:            !is_dilated() && // or dilation
