d check_shape_forward(const at::Tensor\u0026 input,\n652:                                 const c10::ArrayRef\u003cT\u003e\u0026 weight_sizes, const at::Tensor\u0026 bias,\n653:                                 const ConvParams\u003cT\u003e\u0026 params) {\n654:   int64_t k = input.ndimension();\n655:   int64_t weight_dim = weight_sizes.size();\n656:   auto groups = params.groups;\n657:   const auto\u0026 padding = params.padding;\n658:   const auto\u0026 dilation = params.dilation;\n659:   bool transposed = params.transposed;\n660: \n661:   TORCH_CHECK(!params.is_padding_neg(), \"negative padding is not supported\");\n662:   TORCH_CHECK(!params.is_output_padding_neg(), \"negative output_padding is not supported\");\n663:   TORCH_CHECK(!params.is_stride_nonpos(), \"non-positive stride is not supported\");\n664:   TORCH_CHECK(!params.is_dilation_neg(), \"dilation should be greater than zero\");\n665: \n666:   TORCH_CHECK(weight_dim == k,\n667:            \"Expected \", weight_dim, \"-dimensional input for \", weight_dim,\n668:            \"-dimensional weight \", weight_sizes, \", but got \", k, \"-dimensional input of size \",\n669:            at::symint::sizes\u003cT\u003e(input), \" instead\");\n670:   TORCH_CHECK(weight_sizes[0] \u003e= groups,\n671:            \"Given groups=\", groups, \", expected weight to be at least \", groups,\n672:            \" at dimension 0, but got weight of size \", weight_sizes, \" instead\");\n673:   TORCH_CHECK(weight_sizes[0] % groups == 0,\n674:            \"Given groups=\", groups, \", expected weight to be divisible by \",\n675:            groups, \" at dimension 0, but got weight of size [\", weight_sizes,\n676:            \"] instead\");\n677: \n678:   if (!transposed) {\n679:     std::vector\u003cT\u003e input_shape;\n680:     std::vector\u003cT\u003e kernel_shape;\n681:     bool kernel_size_correct = true;\n682: \n683:     TORCH_CHECK(at::symint::size\u003cT\u003e(input, 1) == (weight_sizes[1] * groups),\n684:                 \"Given groups=\", groups, \", weight of size \", weight_sizes,\n685:                 \", expected input\", at::symint::sizes\u003cT\u003e(input), \" to have \",\n686:                 (weight_sizes[1] * groups), \" channels, but got \", at::symint::size\u003cT\u003e(input, 1),\n687:                 \" channels instead\");\n688: \n689:     TORCH_CHECK(!bias.defined() || (bias.ndimension() == 1 \u0026\u0026 at::symint::size\u003cT\u003e(bias, 0) == weight_sizes[0]),\n690:              \"Given weight of size \", weight_sizes,\n691:              \", expected bias to be 1-dimensional with \", weight_sizes[0], \" elements\",\n692:              \", but got bias of size \", at::symint::sizes\u003cT\u003e(bias), \" instead\");\n693: \n694:     for (const auto i : c10::irange(2, k)) {\n695:       input_shape.push_back(at::symint::size\u003cT\u003e(input, i) + 2 * padding[i-2]);\n696:       // log new kernel size considering dilation\n697:       kernel_shape.push_back(dilation[i-2] * (weight_sizes[i]-1) + 1);\n698:       if (input_shape.back() \u003c kernel_shape.back()) {\n699:         kernel_size_correct = false;\n700:       }\n701:     }\n702: \n703:     TORCH_CHECK(input_shape.size() == kernel_shape.size(), \"Inconsistent shape between Input and Kernel\");\n704: \n705:     if (!kernel_size_correct) {\n706:       // If kernel size is incorrect\n707:       std::ostringstream input_ss;\n708:       std::ostringstream kernel_ss;\n709:       std::string separator = \"\";\n710: \n711:       for (int i = 0, len = input_shape.size(); i \u003c len; ++i) {\n712:         input_ss \u003c\u003c separator \u003c\u003c input_shape[i];\n713:         kernel_ss \u003c\u003c separator \u003c\u003c kernel_shape[i];\n714:         separator = \" x \";\n715:       }\n716: \n717:       TORCH_CHECK(false, \"Calculated padded input size per channel: (\", input_ss.str(), \"). \"\n718:                \"Kernel size: (\", kernel_ss.str(), \"). Kernel size can't be greater than actual input size\");\n719:     }\n720:   } else { // transposed\n721:     TORCH_CHECK(at::symint::size\u003cT\u003e(input, 1) == weight_sizes[0],\n722:              \"Given transposed=\", transposed, \", weight of size \", weight_sizes,\n723:              \", expected input\", at::symint::sizes\u003cT\u003e(input), \" to have \", weight_sizes[0],\n724:              \" channels, but got \", at::symint::size\u003cT\u003e(input, 1), \" channels instead\");\n725:     TORCH_CHECK(!bias.defined() || (bias.ndimension() == 1 \u0026\u0026 at::symint::size\u003cT\u003e(bias, 0) == weight_sizes[1] * groups),\n726:              \"Given transposed=\", transposed, \", weight of size \", weight_sizes,\n727:              \", expected bias to be 1-dimensional with \", weight_sizes[1] * groups, \" elements\",\n728:              \", but got bias of size \", at::symint::sizes\u003cT\u003e(bias), \" instead\");\n729:   }\n730: }\n731: \n732: template \u003ctypename T\u003e\n733: static void check_shape_backward(\n734:     const at::Tensor\u0026 input,\n735:     const c10::ArrayRef\u003cT\u003e\u0026 weight_sizes,\n736:     const ConvParams\u003cT\u003e\u0026 params) {\n737:   check_shape_forward\u003cT\u003e(input, weight_sizes, /*bias=*/ Tensor(), params);\n738: }\n739: \n740: // Given an input tensor and an expected number of spatial dimensions, checks that the\n741: // input is a valid shape and returns the batched form of the input.\n742: //\n743: // Args:\n744: //     input (Tensor): Input tensor\n745: //     num_spatial_dims (int): Number of spatial dimensions expected for the input\n746: //     func_name (string): Function name to produce a nice error message for invalid input\n747: //\n748: // Returns a std::tuple containing:\n749: //     batched_input (Tensor): Input with a batch dimension\n750: //     is_batched (bool): Indicates whether the original input was already batched\n751: static std::tuple\u003cTensor, bool\u003e batchify(\n752:     const Tensor\u0026 input,\n753:     const int64_t num_spatial_dims,\n754:     const std::string\u0026 func_name) {\n755:   // assume NTs are always batched\n756:   if (input.is_nested()) {\n757:     return std::make_tuple(input, true);\n758:   }\n759:   const auto dim_count_no_batch = num_spatial_dims + 1;\n760:   const auto dim_count_batch = dim_count_no_batch + 1;\n761:   const auto is_batched = (input.dim() == dim_count_batch);\n762:   TORCH_CHECK(input.dim() == dim_count_no_batch || is_batched,\n763:       \"Expected \", dim_count_no_batch, \"D (unbatched) or \", dim_count_batch,\n764:       \"D (batched) input to \", func_name, \", but got input of size: \", input.sizes());\n765:   return std::make_tuple(is_batched ? input : input.unsqueeze(0), is_batched);\n766: }\n767: \n768: static void check_input_same_type_as_parameters(\n769:     const Tensor\u0026 input,\n770:     const Tensor\u0026 weight,\n771:     const Tensor\u0026 bias) {\n772:   TORCH_CHECK(input.options().type_equal(weight.options()),\n773:       \"Input type (\", input.toString(), \") and weight type (\", weight.toString(),\n774:       \") should be the same\");\n775:   TORCH_CHECK(!bias.defined() || (input.options().type_equal(bias.options())),\n776:       \"Input type (\", input.toString(), \") and bias type (\", bias.toString(),\n777:       \") should be the same\");\n778: }\n779: \n780: static void check_input_same_type_as_parameters(\n781:     const Tensor\u0026 input,\n782:     const Tensor\u0026 weight) {\n783:   check_input_same_type_as_parameters(input, weight, /*bias=*/ Tensor());\n784: }\n785: \n786: #if AT_MKLDNN_ENABLED()\n787: static void check_input_same_type_as_parameters(\n788:     const Tensor\u0026 input,\n789:     const Tensor\u0026 weight,\n790:     const Tensor\u0026 bias,\n791:     const ConvBackend backend) {\n792:   if (backend == ConvBackend::Mkldnn || backend == ConvBackend::MkldnnTranspose) {\n793:     TORCH_CHECK(input.options().type_equal(weight.options())\n794:         || (input.is_mkldnn() \u0026\u0026 weight.device().i