elect(dim_i, 0);\n836:   auto i_i = inp_view_as_complex.select(dim_i, 1);\n837:   return std::make_pair(i_r, i_i);\n838: }\n839: \n840: at::Tensor complex_convolution(\n841:     const Tensor\u0026 input,\n842:     const Tensor\u0026 weight,\n843:     const Tensor\u0026 bias,\n844:     SymIntArrayRef stride,\n845:     SymIntArrayRef padding,\n846:     SymIntArrayRef dilation,\n847:     bool transposed,\n848:     SymIntArrayRef output_padding,\n849:     const c10::SymInt\u0026 groups) {\n850:   check_input_same_type_as_parameters(input, weight, bias);\n851:   auto [i_r, i_i] = complex_to_real(input.resolve_conj());\n852:   auto [w_r, w_i] = complex_to_real(weight.resolve_conj());\n853: \n854:   // [NOTE] Complex Convolution\n855:   // conv(W, x, b) = conv(Wr, xr, br) - conv(Wi, xi, 0) + i(conv(Wi, xr, bi) + conv(Wr, xi, 0))\n856:   // where W, x and b are all complex inputs.\n857:   // With Gauss Trick:\n858:   // a = conv(Wr, xr, br),\n859:   // b = conv(Wi, xi, 0),\n860:   // c = conv(Wr + Wi, xr + xi, bi + br)\n861:   // conv(W, x, b) = a - b + i(c - a - b)\n862:   Tensor a, b, c;\n863:   if (!bias.defined()) {\n864:     a = at::convolution_symint(i_r, w_r, bias, stride, padding, dilation, transposed, output_padding, groups);\n865:     b = at::convolution_symint(i_i, w_i, bias, stride, padding, dilation, transposed, output_padding, groups);\n866:     c = at::convolution_symint(i_r + i_i, w_r + w_i, bias, stride, padding, dilation, transposed, output_padding, groups);\n867:   } else {\n868:     auto [b_r, b_i] = complex_to_real(bias.resolve_conj());\n869:     a = at::convolution_symint(i_r, w_r, b_r, stride, padding, dilation, transposed, output_padding, groups);\n870:     b = at::convolution_symint(i_i, w_i, Tensor(), stride, padding, dilation, transposed, output_padding, groups);\n871:     c = at::convolution_symint(i_r + i_i, w_r + w_i, b_r + b_i, stride, padding, dilation, transposed, output_padding, groups);\n872:   }\n873: \n874:   auto i = c10::Scalar(c10::complex\u003cdouble\u003e(0, 1));\n875:   return a - b + i * (c - a - b);\n876: }\n877: \n878: at::Tensor complex_convolution_mode(\n879:     const at::Tensor\u0026 input,\n880:     const at::Tensor\u0026 weight,\n881:     const std::optional\u003cat::Tensor\u003e\u0026 bias_opt,\n882:     c10::SymIntArrayRef stride,\n883:     std::string_view padding,\n884:     c10::SymIntArrayRef dilation,\n885:     const c10::SymInt\u0026 groups) {\n886:   auto bias = bias_opt.value_or(Tensor());\n887:   check_input_same_type_as_parameters(input, weight, bias);\n888:   auto [i_r, i_i] = complex_to_real(input.resolve_conj());\n889:   auto [w_r, w_i] = complex_to_real(weight.resolve_conj());\n890: \n891:   // See [NOTE] Complex Convolution\n892:   Tensor a, b, c;\n893:   if (!bias.defined()) {\n894:     a = at::_convolution_mode_symint(i_r, w_r, bias, stride, padding, dilation, groups);\n895:     b = at::_convolution_mode_symint(i_i, w_i, bias, stride, padding, dilation, groups);\n896:     c = at::_convolution_mode_symint(i_r + i_i, w_r + w_i, bias, stride, padding, dilation, groups);\n897:   } else {\n898:     auto [b_r, b_i] = complex_to_real(bias.resolve_conj());\n899:     a = at::_convolution_mode_symint(i_r, w_r, b_r, stride, padding, dilation, groups);\n900:     b = at::_convolution_mode_symint(i_i, w_i, Tensor(), stride, padding, dilation, groups);\n901: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/pytorch--5811a8d7@5811a8d7da873dd699ff6687092c225caffcf1bb/-/blob/aten/src/ATen/native/Convolution.cpp%3FL620-900"}", "annotations": null, "meta": null}], "structuredContent": {"content": "620: DEFINE_DISPATCH(mkldnn_convolution_transpose_stub);
