740: // Given an input tensor and an expected number of spatial dimensions, checks that the
741: // input is a valid shape and returns the batched form of the input.
742: //
743: // Args:
744: //     input (Tensor): Input tensor
745: //     num_spatial_dims (int): Number of spatial dimensions expected for the input
746: //     func_name (string): Function name to produce a nice error message for invalid input
747: //
748: // Returns a std::tuple containing:
749: //     batched_input (Tensor): Input with a batch dimension
750: //     is_batched (bool): Indicates whether the original input was already batched
751: static std::tuple<Tensor, bool> batchify(
752:     const Tensor& input,
753:     const int64_t num_spatial_dims,
754:     const std::string& func_name) {
755:   // assume NTs are always batched
756:   if (input.is_nested()) {
757:     return std::make_tuple(input, true);
758:   }
759:   const auto dim_count_no_batch = num_spatial_dims + 1;
760:   const auto dim_count_batch = dim_count_no_batch + 1;
761:   const auto is_batched = (input.dim() == dim_count_batch);
762:   TORCH_CHECK(input.dim() == dim_count_no_batch || is_batched,
763:       "Expected ", dim_count_no_batch, "D (unbatched) or ", dim_count_batch,
764:       "D (batched) input to ", func_name, ", but got input of size: ", input.sizes());
765:   return std::make_tuple(is_batched ? input : input.unsqueeze(0), is_batched);
766: }
