821: static at::Tensor subtensor(at::Tensor& tensor, int64_t dim, int64_t groups, int64_t g) {
822:   if (!tensor.defined()) {
823:     return at::Tensor();
824:   }
825:   const auto memory_format = tensor.suggest_memory_format();
826:   int64_t n = tensor.sizes()[dim] / groups;
827:   return tensor.narrow(dim, n * g, n).contiguous(memory_format);
828: }
